package ua.university.sms.exception;
import org.springframework.http.*;import org.springframework.web.bind.MethodArgumentNotValidException;import org.springframework.web.bind.annotation.*;import java.time.Instant;import java.util.*;
@RestControllerAdvice public class GlobalExceptionHandler{@ExceptionHandler(NotFoundException.class) ResponseEntity<Map<String,Object>> notFound(NotFoundException e){return error(HttpStatus.NOT_FOUND,e.getMessage());}@ExceptionHandler({IllegalArgumentException.class,IllegalStateException.class}) ResponseEntity<Map<String,Object>> bad(RuntimeException e){return error(HttpStatus.BAD_REQUEST,e.getMessage());}@ExceptionHandler(MethodArgumentNotValidException.class) ResponseEntity<Map<String,Object>> validation(MethodArgumentNotValidException e){String msg=e.getBindingResult().getFieldErrors().stream().map(f->f.getField()+": "+f.getDefaultMessage()).toList().toString();return error(HttpStatus.BAD_REQUEST,msg);}private ResponseEntity<Map<String,Object>> error(HttpStatus status,String message){return ResponseEntity.status(status).body(Map.of("timestamp",Instant.now().toString(),"status",status.value(),"error",status.getReasonPhrase(),"message",message));}}
